(function (global) {
  function toPx(value) {
    var n = Number(value);
    return Number.isFinite(n) ? n : 0;
  }

  function getFont(font) {
    var size = toPx(font && font.size ? font.size : 10);
    var family = font && font.family ? font.family : "Arial";
    var weight = font && font.weight ? font.weight + " " : "";
    return weight + size + "px " + family;
  }

  var plugin = {
    id: "datalabels",
    afterDatasetsDraw: function (chart, args, pluginOptions) {
      var options = (chart.options && chart.options.plugins && chart.options.plugins.datalabels) || {};
      var ctx = chart.ctx;
      var datasets = chart.data && chart.data.datasets ? chart.data.datasets : [];

      ctx.save();
      ctx.font = getFont(options.font);
      ctx.fillStyle = options.color || "#ffffff";
      ctx.textAlign = "center";
      ctx.textBaseline = "bottom";

      datasets.forEach(function (dataset, datasetIndex) {
        var meta = chart.getDatasetMeta(datasetIndex);
        if (!meta || meta.hidden) return;

        meta.data.forEach(function (element, dataIndex) {
          if (!element) return;

          var value = dataset.data ? dataset.data[dataIndex] : undefined;
          var context = {
            chart: chart,
            dataIndex: dataIndex,
            dataset: dataset,
            datasetIndex: datasetIndex,
            active: false
          };

          var label = typeof options.formatter === "function"
            ? options.formatter(value, context)
            : value;

          if (label === null || label === undefined || label === "") {
            return;
          }

          if (datasetIndex !== 0) {
            return;
          }

          var props = element.getProps(["x", "y", "base", "width", "height"], true);
          var x = props.x;
          var y = Math.min(props.y, props.base) - 4;

          ctx.fillText(String(label), x, y);
        });
      });

      ctx.restore();
    }
  };

  global.ChartDataLabels = plugin;
})(window);
